{"rawEvent":{"message_id":"019d000460057e52861b9ad3e36d89c1","conversation_id":"019cfea941d2708dab2e8bce0fe6549b","tool_call_id":"call_d38b8e0c-56d4-4ab3-b2da-a9bb3ef7ce04","document":{"file_path":"/Users/junjiecui/AndroidStudioProjects/GroupCreate/app/src/main/java/com/example/groupcreate/MainActivity.kt","sub_content":"MainActivity.kt","sub_content_event":"open_editor","sub_content_event_value":"/Users/junjiecui/AndroidStudioProjects/GroupCreate/app/src/main/java/com/example/groupcreate/MainActivity.kt","sub_content_tip":"/Users/junjiecui/AndroidStudioProjects/GroupCreate/app/src/main/java/com/example/groupcreate/MainActivity.kt","apply_content":"package com.example.groupcreate

import android.Manifest
import android.content.BroadcastReceiver
import android.content.Context
import android.content.IntentFilter
import android.content.pm.PackageManager
import android.net.wifi.p2p.WifiP2pConfig
import android.net.wifi.p2p.WifiP2pManager
import android.net.wifi.p2p.WifiP2pManager.Channel
import android.os.Build
import android.os.Bundle
import android.util.Log
import android.widget.Button
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.activity.result.contract.ActivityResultContracts
import androidx.annotation.RequiresApi
import androidx.annotation.RequiresPermission
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat

class MainActivity : AppCompatActivity() {
 companion object {
 const val TAG = "CJJ_debug"
 }
 private lateinit var wifiP2pManager: WifiP2pManager

 private lateinit var channel: Channel
 private var broadcastReceiver: WiFiDirectBroadcastReceiver? = null

 private lateinit var button: Button

 private val permissionLauncher = registerForActivityResult(
 ActivityResultContracts.RequestMultiplePermissions()
 ) { permissions ->
 if (permissions.all { it.value }) {
 initWifiP2p()
 } else {
 Log.e(TAG, "没有权限")
 for (permission in permissions) {
 Log.e(TAG, "没有权限：${permission.key}")
 }
 Toast.makeText(this, "需要权限才能使用WiFi Direct功能", Toast.LENGTH_LONG).show()
 }
 }

 override fun onCreate(savedInstanceState: Bundle?) {
 super.onCreate(savedInstanceState)
 setContentView(R.layout.activity_main)
 initController()
 checkPermissions()
 }

 private fun initWifiP2p() {
 wifiP2pManager = getSystemService(Context.WIFI_P2P_SERVICE) as WifiP2pManager
 channel = wifiP2pManager.initialize(this, mainLooper, null)
 initBroadcastReceiver()
 Log.d(TAG, "init WifiP2p done")
 }

 private fun initBroadcastReceiver() {
 val intentFilter = IntentFilter().apply {
 addAction(WifiP2pManager.WIFI_P2P_STATE_CHANGED_ACTION)
 addAction(WifiP2pManager.WIFI_P2P_PEERS_CHANGED_ACTION)
 addAction(WifiP2pManager.WIFI_P2P_CONNECTION_CHANGED_ACTION)
 addAction(WifiP2pManager.WIFI_P2P_THIS_DEVICE_CHANGED_ACTION)
 }
 broadcastReceiver = WiFiDirectBroadcastReceiver(wifiP2pManager, channel)
 registerReceiver(broadcastReceiver, intentFilter)
 }

 @RequiresApi(Build.VERSION_CODES.Q)
 private fun initController() {
 button = findViewById(R.id.button)
 button.setOnClickListener {
 createGroup()
 }
 Log.d(TAG, "init Controller done")
 }

 private fun checkPermissions() {
 val requiredPermissions = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
 // Android 10及以上需要NEARBY_WIFI_DEVICES权限
 arrayOf(
 Manifest.permission.ACCESS_WIFI_STATE,
 Manifest.permission.CHANGE_WIFI_STATE,
 Manifest.permission.ACCESS_FINE_LOCATION,
 Manifest.permission.ACCESS_COARSE_LOCATION,
 Manifest.permission.NEARBY_WIFI_DEVICES
 )
 } else {
 // Android 10以下不需要NEARBY_WIFI_DEVICES权限
 arrayOf(
 Manifest.permission.ACCESS_WIFI_STATE,
 Manifest.permission.CHANGE_WIFI_STATE,
 Manifest.permission.ACCESS_FINE_LOCATION,
 Manifest.permission.ACCESS_COARSE_LOCATION
 )
 }

 val missingPermissions = requiredPermissions.filter {
 ContextCompat.checkSelfPermission(this, it) != PackageManager.PERMISSION_GRANTED
 }

 if (missingPermissions.isNotEmpty()) {
 permissionLauncher.launch(missingPermissions.toTypedArray())
 } else {
 initWifiP2p()
 }
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 @RequiresApi(Build.VERSION_CODES.Q)
 private fun createGroup() {
 Log.d(TAG, "create Group start")

 // 检查设备是否支持WiFi Direct
 if (!isWifiDirectSupported()) {
 Log.e(TAG, "设备不支持WiFi Direct功能")
 Toast.makeText(this, "您的设备不支持WiFi Direct功能", Toast.LENGTH_LONG).show()
 return
 }

 val listener = object : WifiP2pManager.ActionListener {
 override fun onSuccess() {
 Log.d(TAG, "create Group success")
 Toast.makeText(this@MainActivity, "创建群组成功", Toast.LENGTH_SHORT).show()
 }

 override fun onFailure(reason: Int) {
 val errorMessage = when (reason) {
 WifiP2pManager.P2P_UNSUPPORTED -> "设备不支持P2P功能"
 WifiP2pManager.BUSY -> "系统繁忙，请稍后重试"
 WifiP2pManager.ERROR -> "内部错误"
 WifiP2pManager.NO_SERVICE_REQUESTS -> "没有服务请求"
 else -> "未知错误，错误代码: $reason"
 }
 Log.e(TAG, "create Group fail: $errorMessage")
 Toast.makeText(this@MainActivity, "创建群组失败: $errorMessage", Toast.LENGTH_LONG).show()
 }
 }

 val config = WifiP2pConfig.Builder()
 .setNetworkName("DIRECT-CJJ")
 .setPassphrase("1234567890")
 .build()

 // 移除旧群组
 removeGroup()
 wifiP2pManager.createGroup(channel, config, listener)
 Log.d(TAG, "create Group done")
 }

 private fun isWifiDirectSupported(): Boolean {
 return packageManager.hasSystemFeature(PackageManager.FEATURE_WIFI_DIRECT)
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 private fun removeGroup() {
 wifiP2pManager.requestGroupInfo(channel) { group ->
 if (group != null) {
 Log.d(TAG, "已有群组存在: ${group.networkName}, 正在移除...")
 wifiP2pManager.removeGroup(channel, object : WifiP2pManager.ActionListener {
 override fun onSuccess() { Log.d(TAG, "移除旧群组成功") }
 override fun onFailure(reason: Int) { 
 val errorMessage = when (reason) {
 WifiP2pManager.P2P_UNSUPPORTED -> "设备不支持P2P功能"
 WifiP2pManager.BUSY -> "系统繁忙，请稍后重试"
 WifiP2pManager.ERROR -> "内部错误"
 else -> "未知错误，错误代码: $reason"
 }
 Log.e(TAG, "移除旧群组失败: $errorMessage") 
 }
 })
 }
 }
 }

 override fun onDestroy() {
 super.onDestroy()
 unregisterReceiver(broadcastReceiver)
 removeGroup()
 }
