 private fun hasRequiredPermissions(): Boolean {
 val requiredPermissions = arrayOf(
 Manifest.permission.ACCESS_FINE_LOCATION,
 Manifest.permission.NEARBY_WIFI_DEVICES
 )
 return requiredPermissions.all {
 ContextCompat.checkSelfPermission(this, it) == PackageManager.PERMISSION_GRANTED
 }
 }

 private fun hasRequiredPermissionsLegacy(): Boolean {
 val requiredPermissions = arrayOf(
 Manifest.permission.ACCESS_FINE_LOCATION
 )
 return requiredPermissions.all {
 ContextCompat.checkSelfPermission(this, it) == PackageManager.PERMISSION_GRANTED
 }
 }

 private fun isWifiDirectSupported(): Boolean {
 return packageManager.hasSystemFeature(PackageManager.FEATURE_WIFI_DIRECT)
 }

 private fun removeGroup() {
 wifiP2pManager.requestGroupInfo(channel) { group ->
 if (group != null) {
 Log.d(TAG, "已有群组存在: ${group.networkName}, 正在移除...")
 wifiP2pManager.removeGroup(channel, object : WifiP2pManager.ActionListener {
 override fun onSuccess() { Log.d(TAG, "移除旧群组成功") }
 override fun onFailure(reason: Int) { 
 val errorMessage = when (reason) {
